49	// ExecutionCleanupMetadata records the ownership metadata for one DDx temp
50	// execution directory.
51	type ExecutionCleanupMetadata struct {
52		ProjectRoot  string `json:"project_root,omitempty"`
53		BeadID       string `json:"bead_id,omitempty"`
54		AttemptID    string `json:"attempt_id,omitempty"`
55		WorktreePath string `json:"worktree_path,omitempty"`
56		Registered   bool   `json:"registered,omitempty"`
57		Preserved    bool   `json:"preserved,omitempty"`
58		// ActiveCandidateCycle is set by AttemptCycleCoordinator while it holds the
59		// worktree open for candidate evaluation (checks, review, repair). The
60		// cleanup manager preserves any worktree with this flag set so it is never
61		// deleted mid-cycle before the coordinator reaches terminal disposition.
62		ActiveCandidateCycle bool `json:"active_candidate_cycle,omitempty"`
63		// Candidate-cycle metadata lets crash recovery distinguish a stale
64		// unpinned worktree from one that still has a project-root candidate ref
65		// worth preserving for operator inspection.
66		CandidateCyclePhase string                    `json:"candidate_cycle_phase,omitempty"`
67		CandidateRef        string                    `json:"candidate_ref,omitempty"`
68		CandidateRev        string                    `json:"candidate_rev,omitempty"`
69		CycleIndex          int                       `json:"cycle_index,omitempty"`
70		ReviewActive        bool                      `json:"review_active,omitempty"`
71		RepairActive        bool                      `json:"repair_active,omitempty"`
72		CreatedAt           time.Time                 `json:"created_at,omitempty"`
73		Liveness            *ExecutionCleanupLiveness `json:"liveness,omitempty"`
74	}
