822	func (m *ExecutionCleanupManager) removeStaleRunState(state RunState, summary *ExecutionCleanupSummary) (bool, int64) {
823		path := runStatePath(m.ProjectRoot)
824		clear := func() error {
825			return ClearRunState(m.ProjectRoot)
826		}
827		if state.AttemptID != "" {
828			if attemptPath, err := runStateAttemptPath(m.ProjectRoot, state.AttemptID); err == nil {
829				path = attemptPath
830				clear = func() error {
831					return ClearRunStateAttempt(m.ProjectRoot, state.AttemptID)
832				}
833			}
834		}
835	
836		var bytes int64
837		present := false
838		if info, statErr := os.Stat(path); statErr == nil {
839			present = true
840			bytes = info.Size()
841		} else if os.IsNotExist(statErr) && path != runStatePath(m.ProjectRoot) {
842			path = runStatePath(m.ProjectRoot)
843			if info, legacyErr := os.Stat(path); legacyErr == nil {
844				present = true
845				bytes = info.Size()
846				clear = func() error {
847					return ClearRunState(m.ProjectRoot)
848				}
849			}
850		}
851		if !m.DryRun {
852			if err := clear(); err != nil {
853				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
854					Path:    path,
855					Class:   "run_state_clear",
856					Message: err.Error(),
857				})
858			}
859		}
860		if !present {
861			return false, 0
862		}
863		class := "removed_run_state"
864		if m.DryRun {
865			class = "would_remove_run_state"
866		}
867		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
868			Path:    path,
869			Class:   class,
870			Message: "stale run-state",
871			Bytes:   bytes,
872			Inodes:  1,
873		})
874		return true, bytes
875	}
