1003	func measureTree(path string) (bytes int64, inodes int64, err error) {
1004		info, err := os.Lstat(path)
1005		if err != nil {
1006			return 0, 0, err
1007		}
1008		if !info.IsDir() {
1009			return info.Size(), 1, nil
1010		}
1011		err = filepath.WalkDir(path, func(p string, d os.DirEntry, walkErr error) error {
1012			if walkErr != nil {
1013				return walkErr
1014			}
1015			inodes++
1016			fi, statErr := d.Info()
1017			if statErr != nil {
1018				return statErr
1019			}
1020			bytes += fi.Size()
1021			return nil
1022		})
1023		return bytes, inodes, err
1024	}
