101	func tryAcquireExecutionCleanupLock(projectRoot string) (func(), bool, error) {
102		lockDir := executionCleanupLockPath(projectRoot)
103		if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
104			return nil, false, fmt.Errorf("execution cleanup: lock dir: %w", err)
105		}
106		if err := os.Mkdir(lockDir, 0o755); err != nil {
107			if breakStaleExecutionCleanupLock(lockDir) {
108				if err := os.Mkdir(lockDir, 0o755); err != nil {
109					return nil, false, nil
110				}
111			} else {
112				return nil, false, nil
113			}
114		}
115		_ = os.WriteFile(filepath.Join(lockDir, "pid"), []byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
116		_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"), []byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
117		return func() { _ = os.RemoveAll(lockDir) }, true, nil
118	}
119	
120	func breakStaleExecutionCleanupLock(lockDir string) bool {
121		pidData, err := os.ReadFile(filepath.Join(lockDir, "pid"))
122		if err == nil {
123			pid := 0
124			if _, scanErr := fmt.Sscanf(string(pidData), "%d", &pid); scanErr == nil && pid > 0 && pid != os.Getpid() {
125				if !trackerProcessAlive(pid) {
126					_ = os.RemoveAll(lockDir)
127					return true
128				}
129			}
130		}
131	
132		acquiredData, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
133		if err == nil {
134			acquired, parseErr := time.Parse(time.RFC3339, string(acquiredData))
135			if parseErr == nil && time.Since(acquired) > trackerLockStaleAge {
136				_ = os.RemoveAll(lockDir)
137				return true
138			}
139		}
140	
141		return false
142	}
