25				loader := &ConfigLoader{workingDir: tmpDir}
26				_, _, _ = loader.DetectConfigFormat()
27				_, _ = ResolveLibraryResource("anchor.md", "", tmpDir)
28			}
29	
30			_ = NewTestConfigForLoop(TestLoopConfigOpts{})
31			_ = NewTestConfigForRun(TestRunConfigOpts{})
32			_ = NewTestConfigForBead(TestBeadConfigOpts{})
33			_ = TestBeadOverrides(TestBeadConfigOpts{})
34			_ = TestLoopOverrides(TestLoopConfigOpts{})
35		})
