191	// NewExecutionCleanupManager constructs a cleanup manager with the default
192	// DDx temp worktree root and the default liveness probe.
193	func NewExecutionCleanupManager(projectRoot string, gitOps GitOps) *ExecutionCleanupManager {
194		return &ExecutionCleanupManager{
195			ProjectRoot: projectRoot,
