203	// Cleanup scans the configured DDx temp worktree root, consults the project
204	// run-state file and git worktree registry, and conservatively removes stale
205	// DDx-owned temp resources.
206	func (m *ExecutionCleanupManager) Cleanup(ctx context.Context) (ExecutionCleanupSummary, error) {
207		_ = ctx
208	
209		summary := ExecutionCleanupSummary{
210			ProjectRoot: m.ProjectRoot,
211			TempRoot:    m.tempRoot(),
212		}
213		if summary.TempRoot == "" {
214			summary.TempRoot = executionCleanupTempRoot(m.ProjectRoot)
215		}
216		if summary.TempRoot == "" {
217			return summary, errors.New("execution cleanup: temp root is empty")
218		}
219		if m.ProjectRoot == "" {
220			return summary, errors.New("execution cleanup: project root is empty")
221		}
222		now := time.Now
223		if m.Now != nil {
224			now = m.Now
225		}
226		probe := m.Probe
227		if probe == nil {
228			probe = defaultExecutionCleanupLivenessProbe{}
229		}
230	
231		registered := map[string]struct{}{}
232		liveRunStates := map[string]struct{}{}
233		if m.GitOps != nil {
234			paths, err := m.GitOps.WorktreeList(m.ProjectRoot)
235			if err != nil {
236				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
237					Path:    m.ProjectRoot,
238					Class:   "git_worktree_list",
239					Message: err.Error(),
240				})
241			} else {
242				for _, p := range paths {
243					registered[filepath.Clean(p)] = struct{}{}
244				}
245			}
246		}
247	
248		runStates, runStateErr := ReadRunStates(m.ProjectRoot)
249		if runStateErr != nil {
250			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
251				Path:    runStateDirPath(m.ProjectRoot),
252				Class:   "run_state_read",
253				Message: runStateErr.Error(),
254			})
255		}
256	
257		entries, err := os.ReadDir(summary.TempRoot)
258		if err != nil {
259			return summary, fmt.Errorf("execution cleanup: read temp root: %w", err)
260		}
261		for _, entry := range entries {
262			if !entry.IsDir() {
263				continue
264			}
265			if !strings.HasPrefix(entry.Name(), ExecuteBeadWtPrefix) {
266				continue
267			}
268			summary.ScannedTempDirs++
269			path := filepath.Join(summary.TempRoot, entry.Name())
270	
271			meta, metaErr := ReadExecutionCleanupMetadata(path)
272			missingMetadata := false
273			if metaErr != nil {
274				if errors.Is(metaErr, os.ErrNotExist) {
275					missingMetadata = true
276					meta = ExecutionCleanupMetadata{
277						ProjectRoot:  m.ProjectRoot,
278						WorktreePath: path,
279					}
280				} else {
281					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
282						Path:    path,
283						Class:   "metadata_read",
284						Message: metaErr.Error(),
285					})
286					continue
287				}
288			}
289			candidateRunStates := runStates
290			ownershipMismatch := meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot)
291			if ownershipMismatch {
292				candidateRunStates = m.runStatesForMetadata(meta, runStates, &summary)
293			}
294	
295			matchedRunState := matchingRunStateForMeta(candidateRunStates, meta)
296			live, reason := probe.IsLive(meta, matchedRunState, now())
297			if live {
298				if matchedRunState != nil {
299					liveRunStates[runStateLiveKey(*matchedRunState)] = struct{}{}
300				}
301				class := "preserved_temp_dir"
302				if isLiveAttemptPreservation(reason) {
303					class = "preserved_live_attempt"
304				}
305				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
306					Path:    path,
307					Class:   class,
308					Message: reason,
309				})
310				continue
311			}
312			if ownershipMismatch {
313				if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, path) {
314					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
315						Path:    path,
316						Class:   "ownership_mismatch",
317						Message: fmt.Sprintf("metadata project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
318					})
319					continue
320				}
321				if m.isRegisteredWorktree(meta.ProjectRoot, path, &summary) {
322					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
323						Path:    path,
324						Class:   "preserved_foreign_registered_worktree",
325						Message: "foreign project worktree is still registered",
326					})
327					continue
328				}
329			}
330	
331			if _, ok := registered[filepath.Clean(path)]; ok {
332				if missingMetadata {
333					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
334						Path:    path,
335						Class:   "registered_missing_metadata",
336						Message: "registered DDx worktree has no cleanup metadata; preserving",
337					})
338					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
339						Path:    path,
340						Class:   "preserved_registered_missing_metadata",
341						Message: "registered worktree without cleanup metadata",
342					})
343					continue
344				}
345				if m.GitOps == nil {
346					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
347						Path:     path,
348						Class:    "registered_worktree",
349						Message:  "no git ops available to remove registered worktree",
350						Blocking: true,
351					})
352					continue
353				}
354				reclaimedBytes, reclaimedInodes, measureErr := measureTree(path)
355				if measureErr != nil {
356					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
357						Path:    path,
358						Class:   "measure_tree",
359						Message: measureErr.Error(),
360					})
361				}
362				if !m.DryRun {
363					if err := m.GitOps.WorktreeRemove(m.ProjectRoot, path); err != nil {
364						summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
365							Path:     path,
366							Class:    "registered_worktree_remove",
367							Message:  err.Error(),
368							Blocking: true,
369						})
370						continue
371					}
372				}
373				summary.RemovedRegisteredWorktrees++
374				summary.BytesReclaimed += reclaimedBytes
375				summary.InodesReclaimed += reclaimedInodes
376				class := "removed_registered_worktree"
377				if m.DryRun {
378					class = "would_remove_registered_worktree"
379				}
380				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
381					Path:    path,
382					Class:   class,
383					Message: reason,
384					Bytes:   reclaimedBytes,
385					Inodes:  reclaimedInodes,
386				})
387				continue
388			}
389	
390			reclaimedBytes, reclaimedInodes, measureErr := measureTree(path)
391			if measureErr != nil {
392				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
393					Path:    path,
394					Class:   "measure_tree",
395					Message: measureErr.Error(),
396				})
397			}
398			if !m.DryRun {
399				if err := os.RemoveAll(path); err != nil {
400					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
401						Path:     path,
402						Class:    "unregistered_temp_dir_remove",
403						Message:  err.Error(),
404						Blocking: false,
405					})
406					continue
407				}
408			}
409			summary.RemovedUnregisteredTempDirs++
410			summary.BytesReclaimed += reclaimedBytes
411			summary.InodesReclaimed += reclaimedInodes
412			class := "removed_unregistered_temp_dir"
413			if m.DryRun {
414				class = "would_remove_unregistered_temp_dir"
415			}
416			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
417				Path:    path,
418				Class:   class,
419				Message: reason,
420				Bytes:   reclaimedBytes,
421				Inodes:  reclaimedInodes,
422			})
423		}
424	
425		m.cleanupScratchRoots(&summary, runStates, registered, probe, now())
426	
427		if m.GitOps != nil && summary.RemovedRegisteredWorktrees > 0 && !m.DryRun {
428			if err := m.GitOps.WorktreePrune(m.ProjectRoot); err != nil {
429				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
430					Path:    m.ProjectRoot,
431					Class:   "worktree_prune",
432					Message: err.Error(),
433				})
434			}
435		}
436	
437		// Stale run-state files are removed when they point at an execution
438		// resource that is no longer live.
439		for _, state := range runStates {
440			if _, ok := liveRunStates[runStateLiveKey(state)]; ok {
441				continue
442			}
443			if runStateWorktreeStillExists(state) {
444				continue
445			}
446			if removed, bytes := m.removeStaleRunState(state, &summary); removed {
447				summary.RemovedRunStateFiles++
448				summary.BytesReclaimed += bytes
449				summary.InodesReclaimed++
450			}
451		}
452	
453		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ExecuteBeadArtifactDir, "manifest.json", "result.json", &summary)
454		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ".ddx/runs", "record.json", "", &summary)
455		m.cleanupDurableLandedCandidateRefs(&summary)
456	
457		return summary, nil
458	}
