460	func (m *ExecutionCleanupManager) cleanupScratchRoots(summary *ExecutionCleanupSummary, runStates []RunState, registered map[string]struct{}, probe ExecutionCleanupLivenessProbe, now time.Time) {
461		prefixes := m.scratchPrefixes()
462		minAge := m.scratchMinAge()
463		tempRoot := filepath.Clean(summary.TempRoot)
464	
465		for _, root := range m.scratchRoots(summary.TempRoot) {
466			entries, err := os.ReadDir(root)
467			if err != nil {
468				if !os.IsNotExist(err) {
469					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
470						Path:    root,
471						Class:   "scratch_root_read",
472						Message: err.Error(),
473					})
474				}
475				continue
476			}
477			for _, entry := range entries {
478				if !entry.IsDir() || !hasAnyPrefix(entry.Name(), prefixes) {
479					continue
480				}
481				path := filepath.Join(root, entry.Name())
482				if sameCleanPath(path, tempRoot) || isPathWithin(path, tempRoot) {
483					continue
484				}
485				summary.ScannedScratchDirs++
486	
487				info, err := entry.Info()
488				if err != nil {
489					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
490						Path:    path,
491						Class:   "scratch_stat",
492						Message: err.Error(),
493					})
494					continue
495				}
496	
497				meta, metaErr := ReadExecutionCleanupMetadata(path)
498				if metaErr != nil {
499					if !errors.Is(metaErr, os.ErrNotExist) {
500						summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
501							Path:    path,
502							Class:   "scratch_metadata_read",
503							Message: metaErr.Error(),
504						})
505						continue
506					}
507					meta = ExecutionCleanupMetadata{
508						ProjectRoot:  m.ProjectRoot,
509						WorktreePath: path,
510					}
511				}
512				if meta.WorktreePath == "" {
513					meta.WorktreePath = path
514				}
515	
516				candidateRunStates := runStates
517				if meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot) {
518					if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, path) {
519						summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
520							Path:    path,
521							Class:   "scratch_ownership_mismatch",
522							Message: fmt.Sprintf("metadata project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
523						})
524						continue
525					}
526					candidateRunStates = m.runStatesForMetadata(meta, runStates, summary)
527					if m.isRegisteredWorktree(meta.ProjectRoot, path, summary) {
528						summary.PreservedActiveScratchDirs++
529						summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
530							Path:    path,
531							Class:   "preserved_active_scratch_dir",
532							Message: "foreign project worktree is still registered",
533						})
534						continue
535					}
536				}
537				if _, ok := registered[filepath.Clean(path)]; ok {
538					summary.PreservedActiveScratchDirs++
539					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
540						Path:    path,
541						Class:   "preserved_active_scratch_dir",
542						Message: "registered worktree",
543					})
544					continue
545				}
546	
547				matchedRunState := matchingRunStateForMeta(candidateRunStates, meta)
548				if live, reason := probe.IsLive(meta, matchedRunState, now); live {
549					summary.PreservedActiveScratchDirs++
550					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
551						Path:    path,
552						Class:   "preserved_active_scratch_dir",
553						Message: reason,
554					})
555					continue
556				}
557	
558				if age := now.Sub(info.ModTime()); age < minAge {
559					summary.PreservedActiveScratchDirs++
560					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
561						Path:    path,
562						Class:   "preserved_active_scratch_dir",
563						Message: fmt.Sprintf("fresh scratch dir age=%s min_age=%s", age.Round(time.Second), minAge),
564					})
565					continue
566				}
567	
568				reclaimedBytes, reclaimedInodes, measureErr := measureTree(path)
569				if measureErr != nil {
570					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
571						Path:    path,
572						Class:   "scratch_measure_tree",
573						Message: measureErr.Error(),
574					})
575				}
576				if !m.DryRun {
577					if err := os.RemoveAll(path); err != nil {
578						summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
579							Path:     path,
580							Class:    "scratch_dir_remove",
581							Message:  err.Error(),
582							Blocking: false,
583						})
584						continue
585					}
586				}
587				summary.RemovedScratchDirs++
588				summary.ScratchBytesReclaimed += reclaimedBytes
589				summary.ScratchInodesReclaimed += reclaimedInodes
590				summary.BytesReclaimed += reclaimedBytes
591				summary.InodesReclaimed += reclaimedInodes
592				class := "removed_scratch_dir"
593				if m.DryRun {
594					class = "would_remove_scratch_dir"
595				}
596				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
597					Path:    path,
598					Class:   class,
599					Message: "stale DDx scratch dir",
600					Bytes:   reclaimedBytes,
601					Inodes:  reclaimedInodes,
602				})
603			}
604		}
605	}
