680	func cleanUniquePaths(paths []string) []string {
681		seen := map[string]struct{}{}
682		var out []string
683		for _, p := range paths {
684			if p == "" {
685				continue
686			}
687			clean := filepath.Clean(p)
688			if _, ok := seen[clean]; ok {
689				continue
690			}
691			seen[clean] = struct{}{}
692			out = append(out, clean)
693		}
694		return out
695	}
