713	func isPathWithin(path, root string) bool {
714		if path == "" || root == "" {
715			return false
716		}
717		cleanPath := filepath.Clean(path)
718		cleanRoot := filepath.Clean(root)
719		if cleanPath == cleanRoot {
720			return true
721		}
722		rel, err := filepath.Rel(cleanRoot, cleanPath)
723		if err != nil {
724			return false
725		}
726		return rel != "." && rel != ".." && !strings.HasPrefix(rel, ".."+string(os.PathSeparator))
727	}
