729	func matchingRunStateForMeta(states []RunState, meta ExecutionCleanupMetadata) *RunState {
730		if meta.CandidateRef != "" {
731			for i := range states {
732				state := states[i]
733				if state.CandidateRef != meta.CandidateRef {
734					continue
735				}
736				if meta.CycleIndex != 0 && state.CycleIndex != meta.CycleIndex {
737					continue
738				}
739				return &states[i]
740			}
741		}
742		for i := range states {
743			state := states[i]
744			if meta.AttemptID != "" && state.AttemptID == meta.AttemptID {
745				return &states[i]
746			}
747			if meta.WorktreePath != "" && state.WorktreePath != "" && filepath.Clean(state.WorktreePath) == filepath.Clean(meta.WorktreePath) {
748				return &states[i]
749			}
750		}
751		return nil
752	}
