754	func isLiveAttemptPreservation(reason string) bool {
755		if strings.HasPrefix(reason, "active candidate cycle") || strings.HasPrefix(reason, "candidate ref recovery") {
756			return true
757		}
758		switch reason {
759		case "matched live run-state", "unexpired liveness", "fresh liveness", "live pid", "active candidate cycle":
760			return true
761		default:
762			return false
763		}
764	}
