770		}
771		if meta.CandidateRef != "" {
772			parts = append(parts, "candidate_ref="+meta.CandidateRef)
773		}
774		if meta.CandidateRev != "" {
775			parts = append(parts, "candidate_rev="+meta.CandidateRev)
776		}
777		if meta.ReviewActive {
778			parts = append(parts, "review_active=true")
779		}
780		if meta.RepairActive {
