896	func (m *ExecutionCleanupManager) cleanupDurableLandedCandidateRefs(summary *ExecutionCleanupSummary) {
897		if m == nil || m.GitOps == nil || m.ProjectRoot == "" {
898			return
899		}
900		resultRoot := filepath.Join(m.ProjectRoot, filepath.FromSlash(ExecuteBeadArtifactDir))
901		entries, err := os.ReadDir(resultRoot)
902		if err != nil {
903			return
904		}
905		seen := map[string]struct{}{}
906		for _, entry := range entries {
907			if !entry.IsDir() {
908				continue
909			}
910			resultPath := filepath.Join(resultRoot, entry.Name(), "result.json")
911			data, readErr := os.ReadFile(resultPath)
912			if readErr != nil {
913				continue
914			}
915			var meta candidateRefResultMetadata
916			if err := json.Unmarshal(data, &meta); err != nil {
917				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
918					Path:    resultPath,
919					Class:   "candidate_ref_result_parse",
920					Message: err.Error(),
921				})
922				continue
923			}
924			if !candidateRefResultDurable(meta) {
925				continue
926			}
927			if _, ok := seen[meta.CandidateRef]; ok {
928				continue
929			}
930			seen[meta.CandidateRef] = struct{}{}
931			if _, err := m.GitOps.ResolveRev(m.ProjectRoot, meta.CandidateRef); err != nil {
932				continue
933			}
934			if !m.DryRun {
935				if err := m.GitOps.DeleteRef(m.ProjectRoot, meta.CandidateRef); err != nil {
936					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
937						Path:    meta.CandidateRef,
938						Class:   "candidate_ref_prune",
939						Message: err.Error(),
940					})
941					continue
942				}
943			}
944			summary.PrunedCandidateRefs++
945			class := "pruned_candidate_ref"
946			if m.DryRun {
947				class = "would_prune_candidate_ref"
948			}
949			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
950				Path:    meta.CandidateRef,
951				Class:   class,
952				Message: "landed candidate metadata durable in " + filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, entry.Name(), "result.json")),
953			})
954		}
955	}
