1026	func scanCompleteEvidenceDirs(projectRoot, rootRel string, primaryFile, secondaryFile string, summary *ExecutionCleanupSummary) int {
1027		root := filepath.Join(projectRoot, filepath.FromSlash(rootRel))
1028		entries, err := os.ReadDir(root)
1029		if err != nil {
1030			return 0
1031		}
1032		count := 0
1033		for _, entry := range entries {
1034			if !entry.IsDir() {
1035				continue
1036			}
1037			count++
1038			full := filepath.Join(root, entry.Name())
1039			complete := false
1040			if primaryFile != "" {
1041				if _, err := os.Stat(filepath.Join(full, primaryFile)); err == nil {
1042					complete = true
1043				}
1044			}
1045			if !complete && secondaryFile != "" {
1046				if _, err := os.Stat(filepath.Join(full, secondaryFile)); err == nil {
1047					complete = true
1048				}
1049			}
1050			if complete {
1051				summary.CompleteEvidenceDirs++
1052				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1053					Path:    filepath.ToSlash(filepath.Join(rootRel, entry.Name())),
1054					Class:   "complete_evidence",
1055					Message: "complete evidence preserved",
1056				})
1057			}
1058		}
1059		return count
1060	}
