13	const defaultExecutionCleanupInterval = 10 * time.Minute
14	const executionCleanupJitterFraction = 0.20
15	
16	const executionCleanupLockDirName = ".cleanup.lock"
17	
18	func executionCleanupLockPath(projectRoot string) string {
19		return filepath.Join(projectRoot, ".ddx", executionCleanupLockDirName)
20	}
21	
22	// runExecutionCleanupPass conservatively runs the shared cleanup manager under
23	// a project-level lock. When another process already owns the lock, the pass
24	// is skipped and observed rather than blocking concurrent deletion.
25	func runExecutionCleanupPass(ctx context.Context, projectRoot string, runner executionCleanupRunner, log io.Writer, emit func(string, map[string]any), reason string) (ExecutionCleanupSummary, bool, error) {
26		if runner == nil {
27			return ExecutionCleanupSummary{}, false, nil
28		}
29		if projectRoot == "" {
30			return ExecutionCleanupSummary{}, false, fmt.Errorf("execution cleanup: project root is empty")
31		}
32	
33		release, acquired, err := tryAcquireExecutionCleanupLock(projectRoot)
34		if err != nil {
35			return ExecutionCleanupSummary{}, false, err
36		}
37		if !acquired {
38			if emit != nil {
39				emit("cleanup.skipped", map[string]any{
40					"project_root": projectRoot,
41					"reason":       reason,
42					"lock_path":    executionCleanupLockPath(projectRoot),
43				})
44			}
45			return ExecutionCleanupSummary{}, true, nil
46		}
47		defer release()
48	
49		summary, runErr := runner.Cleanup(ctx)
50		meaningful := executionCleanupSummaryMeaningful(summary)
51	
52		if emit != nil && meaningful {
53			emit("cleanup.pass", map[string]any{
54				"project_root":                summary.ProjectRoot,
55				"temp_root":                   summary.TempRoot,
56				"reason":                      reason,
57				"scanned_temp_dirs":           summary.ScannedTempDirs,
58				"scanned_evidence_dirs":       summary.ScannedEvidenceDirs,
59				"complete_evidence_dirs":      summary.CompleteEvidenceDirs,
60				"scanned_scratch_dirs":        summary.ScannedScratchDirs,
61				"removed_unregistered":        summary.RemovedUnregisteredTempDirs,
62				"removed_registered_worktree": summary.RemovedRegisteredWorktrees,
63				"removed_run_state":           summary.RemovedRunStateFiles,
64				"removed_scratch_dirs":        summary.RemovedScratchDirs,
65				"preserved_scratch_dirs":      summary.PreservedActiveScratchDirs,
66				"bytes_reclaimed":             summary.BytesReclaimed,
67				"inodes_reclaimed":            summary.InodesReclaimed,
68				"scratch_bytes_reclaimed":     summary.ScratchBytesReclaimed,
69				"scratch_inodes_reclaimed":    summary.ScratchInodesReclaimed,
70				"warnings":                    len(summary.Warnings),
71				"issues":                      len(summary.Issues),
72			})
73		}
74		if meaningful && log != nil {
75			fmt.Fprintf(log, "cleanup: %s %d temp dir(s), %d worktree(s), %d run-state file(s), %d scratch dir(s), %d byte(s), %d inode(s)\n",
76				reason,
77				summary.RemovedUnregisteredTempDirs,
78				summary.RemovedRegisteredWorktrees,
79				summary.RemovedRunStateFiles,
80				summary.RemovedScratchDirs,
81				summary.BytesReclaimed+summary.ScratchBytesReclaimed,
82				summary.InodesReclaimed+summary.ScratchInodesReclaimed,
83			)
84		}
85		return summary, false, runErr
86	}
87	
88	func executionCleanupSummaryMeaningful(summary ExecutionCleanupSummary) bool {
89		return len(summary.Issues) > 0 ||
90			summary.BytesReclaimed > 0 ||
91			summary.InodesReclaimed > 0 ||
92			summary.ScratchBytesReclaimed > 0 ||
93			summary.ScratchInodesReclaimed > 0 ||
94			summary.RemovedUnregisteredTempDirs > 0 ||
95			summary.RemovedRegisteredWorktrees > 0 ||
96			summary.RemovedRunStateFiles > 0 ||
97			summary.RemovedScratchDirs > 0 ||
98			summary.PreservedActiveScratchDirs > 0
99	}
