144	func jitteredCleanupDelay(base time.Duration, rng *rand.Rand) time.Duration {
145		if base <= 0 {
146			return 0
147		}
148		if rng == nil {
149			rng = rand.New(rand.NewSource(time.Now().UnixNano()))
150		}
151		if executionCleanupJitterFraction <= 0 {
152			return base
153		}
154		jitter := time.Duration(float64(base) * executionCleanupJitterFraction)
155		if jitter <= 0 {
156			return base
157		}
158		span := int64(jitter) * 2
159		if span <= 0 {
160			return base
161		}
162		offset := time.Duration(rng.Int63n(span+1)) - jitter
163		delay := base + offset
164		if delay < time.Second {
165			delay = time.Second
166		}
167		return delay
168	}
169	
170	func startExecutionCleanupWorker(ctx context.Context, projectRoot string, runner executionCleanupRunner, interval time.Duration, tickCh <-chan time.Time, log io.Writer, emit func(string, map[string]any)) (stop func()) {
171		if runner == nil {
172			return func() {}
173		}
174		if interval <= 0 {
175			interval = defaultExecutionCleanupInterval
176		}
177	
178		workerCtx, cancel := context.WithCancel(ctx)
179		done := make(chan struct{})
180		go func() {
181			defer close(done)
182			var rng *rand.Rand
183			if tickCh == nil {
184				rng = rand.New(rand.NewSource(time.Now().UnixNano()))
185			}
186			for {
187				if tickCh != nil {
188					select {
189					case <-workerCtx.Done():
190						_, _, _ = runExecutionCleanupPass(context.Background(), projectRoot, runner, log, emit, "shutdown")
191						return
192					case <-tickCh:
193						_, _, _ = runExecutionCleanupPass(workerCtx, projectRoot, runner, log, emit, "periodic")
194					}
195					continue
196				}
197	
198				timer := time.NewTimer(jitteredCleanupDelay(interval, rng))
199				select {
200				case <-workerCtx.Done():
201					timer.Stop()
202					_, _, _ = runExecutionCleanupPass(context.Background(), projectRoot, runner, log, emit, "shutdown")
203					return
204				case <-timer.C:
205					_, _, _ = runExecutionCleanupPass(workerCtx, projectRoot, runner, log, emit, "periodic")
206				}
207			}
208		}()
209	
210		return func() {
211			cancel()
212			<-done
213		}
214	}
