13	// RoutingMigrationError signals that the loaded config carries a removed
14	// agent.routing field. The field is gone for good; configs must be migrated
15	// before DDx will load them.
16	type RoutingMigrationError struct {
17		Field string
18		Path  string
19	}
20	
21	func (e *RoutingMigrationError) Error() string {
22		return fmt.Sprintf(
23			"%s: %s has been removed. "+
24				"Migration: delete the field from your .ddx/config.yaml. "+
25				"See docs/migrations/routing-config.md.",
26			e.Path, e.Field)
27	}
