150	// Validate validates the configuration structure and values (simplified)
151	func (c *Config) Validate() error {
152		var errors []*ConfigError
153	
154		// Validate version
155		if c.Version == "" {
156			errors = append(errors, &ConfigError{
157				Field:      "version",
158				Message:    "version is required",
159				Suggestion: "add 'version: \"1.0\"' to your config",
160			})
161		}
162	
163		// Validate library configuration
164		if c.Library != nil && c.Library.Repository != nil {
165			if c.Library.Repository.URL == "" {
166				errors = append(errors, &ConfigError{
167					Field:      "library.repository.url",
168					Message:    "library repository URL is required",
169					Suggestion: "add a valid Git repository URL",
170				})
171			}
172	
173			if c.Library.Repository.Branch == "" {
174				errors = append(errors, &ConfigError{
175					Field:      "library.repository.branch",
176					Message:    "library repository branch is required",
177					Suggestion: "add 'branch: \"main\"' or another valid branch name",
178				})
179			}
180		}
181	
182		if c.Triage != nil {
183			for mode, actions := range c.Triage.Policies {
184				if _, err := triage.ParseFailureMode(mode); err != nil {
185					errors = append(errors, &ConfigError{
186						Field:      "triage.policies." + mode,
187						Value:      mode,
188						Message:    err.Error(),
189						Suggestion: "use review_block, lock_contention, execution_failed, or no_changes",
190					})
191					continue
192				}
193				for i, action := range actions {
194					if _, err := triage.ParseAction(action); err != nil {
195						errors = append(errors, &ConfigError{
196							Field:      fmt.Sprintf("triage.policies.%s[%d]", mode, i),
197							Value:      action,
198							Message:    err.Error(),
199							Suggestion: "use re_attempt_with_context, escalate_tier, retry_with_backoff, file_followup, or operator_required",
200						})
201					}
202				}
203			}
204		}
205	
206		if len(errors) > 0 {
207			return &ValidationError{Errors: errors}
208		}
209	
210		return nil
211	}
