259	// ResolveLibraryResource resolves a library resource path
260	// NOTE: This function is now legacy. New code should load config and use cfg.Library.Path directly.
261	func ResolveLibraryResource(resourcePath, configPath, workingDir string) (string, error) {
262		// Load config to get the authoritative library path (which includes env var override)
263		cfg, err := LoadWithWorkingDir(workingDir)
264		if err == nil && cfg.Library != nil && cfg.Library.Path != "" {
265			// Check if it's an absolute path
266			if filepath.IsAbs(resourcePath) {
267				return resourcePath, nil
268			}
269	
270			// Try relative to library path from config
271			configPath := filepath.Join(cfg.Library.Path, resourcePath)
272			if _, err := os.Stat(configPath); err == nil {
273				return configPath, nil
274			}
275	
276			// Return the config path even if it doesn't exist (for consistency)
277			return configPath, nil
278		}
279	
280		// Fall back to original logic if config loading fails
281		if workingDir == "" {
282			workingDir, err = os.Getwd()
283			if err != nil {
284				return "", err
285			}
286		}
287	
288		// Check if it's an absolute path
289		if filepath.IsAbs(resourcePath) {
290			return resourcePath, nil
291		}
292	
293		// Try relative to working directory first
294		fullPath := filepath.Join(workingDir, resourcePath)
295		if _, err := os.Stat(fullPath); err == nil {
296			return fullPath, nil
297		}
298	
299		// Try relative to library directory
300		libraryPath := filepath.Join(workingDir, "library", resourcePath)
301		if _, err := os.Stat(libraryPath); err == nil {
302			return libraryPath, nil
303		}
304	
305		// Return the original path even if it doesn't exist
306		return fullPath, nil
307	}
