11	// ExecutionWorktreeRoot returns the configured base directory for isolated
12	// execute-bead worktrees. Resolution order matches the operator-facing config
13	// priority: environment override, project config, global config, then caller
14	// fallback.
15	func ExecutionWorktreeRoot(projectRoot string) string {
16		if env := strings.TrimSpace(os.Getenv(ExecutionWorktreeRootEnv)); env != "" {
17			return normalizeExecutionWorktreeRoot(env, projectRoot)
18		}
19		if projectRoot != "" {
20			projectConfig := filepath.Join(projectRoot, ".ddx", "config.yaml")
21			if root := executionWorktreeRootFromFile(projectConfig, projectRoot); root != "" {
22				return root
23			}
24		}
25		home, err := os.UserHomeDir()
26		if err == nil && home != "" {
27			globalConfig := filepath.Join(home, ".ddx", "config.yaml")
28			if root := executionWorktreeRootFromFile(globalConfig, home); root != "" {
29				return root
30			}
31		}
32		return ""
33	}
